-- Demo fixture for the accounts-service isolation reproduce (compose-accounts-iso.yml).
-- 80 accounts extracted from a real eBPF capture (banking-accounts /api/accounts/{id} 200s)
-- so /balance returns real captured data with zero stack. Apply AFTER accounts-service is
-- healthy (its Flyway migration creates accounts_service.accounts):
--   docker exec -i acct-iso-postgres psql -U postgres -d banking_app < database/seeds/accounts-demo-seed.sql

SET search_path TO accounts_service;
ON CONFLICT (id) DO UPDATE SET balance=EXCLUDED.balance, user_id=EXCLUDED.user_id;
SELECT setval(pg_get_serial_sequence('accounts','id'), (SELECT MAX(id) FROM accounts));
